/// sample.png → decode (U16, lossless) → rotate90 CW → compare against vips golden.
///
/// vips command: vips rot sample.png tools/.fixture-work/rot.v d90 && vips rawsave tools/.fixture-work/rot.v png_rotate90.bin
#[test]
#[cfg(feature = "png")]
fn png_rotate90_matches_vips() {
    use viprs::{adapters::codecs::PngCodec, domain::format::U16, ports::codec::ImageDecoder};

    let src_bytes = fixture_image("sample.png");
    let codec = PngCodec::default();
    let decoded = codec.decode::<U16>(&src_bytes).expect("PNG decode failed");

    let width = decoded.width();
    let height = decoded.height();
    let bands = decoded.bands();

    let source = MemorySource::<U16>::new(width, height, bands, decoded.pixels().to_vec())
        .expect("MemorySource failed");

    let pipeline = PipelineBuilder::from_source(source)
        .rotate90()
        .expect("rotate90 step failed")
        .build()
        .expect("pipeline build failed");

    let mut sink = MemorySink::for_pipeline(&pipeline).unwrap();
    RayonScheduler::new(1)
        .expect("scheduler failed")
        .run(&pipeline, &mut sink)
        .expect("pipeline run failed");

    let actual = sink.into_buffer();
    let expected = golden_bin("png_rotate90.bin");

    assert_eq!(
        actual.len(),
        expected.len(),
        "png_rotate90: length mismatch — got {} bytes ({}×{}×{}×2), expected {}",
        actual.len(),
        pipeline.width,
        pipeline.height,
        pipeline.output_bands,
        expected.len()
    );
    assert_eq!(
        actual, expected,
        "png_rotate90: pixel-exact mismatch against vips golden"
    );
}

// ── JPEG: invert ─────────────────────────────────────────────────────────────

/// sample.jpg → decode (U8, libjpeg-turbo) → invert → compare against vips golden with tolerance.
///
/// vips command: vips invert sample.jpg tools/.fixture-work/jinv.v && vips rawsave tools/.fixture-work/jinv.v jpeg_invert.bin
///
/// Tolerance ±1 per channel: both pipelines use libjpeg-turbo, but the wrappers are independent.
/// This fixture should stay within a single quantized sample so larger deltas
/// surface meaningful regressions instead of being masked.
#[test]
#[ignore] // issue #24: JPEG invert output differs from libvips by up to 16 sample values
#[cfg(feature = "jpeg")]
fn jpeg_invert_matches_vips() {
    // Validates JPEG parity against the vips golden with a tight tolerance so
    // codec or pipeline regressions cannot hide behind an overly broad threshold.
    use viprs::{adapters::codecs::JpegCodec, domain::format::U8, ports::codec::ImageDecoder};

    let src_bytes = fixture_image("sample.jpg");
    let codec = JpegCodec;
    let decoded = codec.decode::<U8>(&src_bytes).expect("JPEG decode failed");

    let width = decoded.width();
    let height = decoded.height();
    let bands = decoded.bands();

    let source = MemorySource::<U8>::new(width, height, bands, decoded.pixels().to_vec())
        .expect("MemorySource failed");

    let pipeline = PipelineBuilder::from_source(source)
        .invert()
        .expect("invert step failed")
        .build()
        .expect("pipeline build failed");

    let mut sink = MemorySink::for_pipeline(&pipeline).unwrap();
    RayonScheduler::new(1)
        .expect("scheduler failed")
        .run(&pipeline, &mut sink)
        .expect("pipeline run failed");

    let actual = sink.into_buffer();
    let expected = golden_bin("jpeg_invert.bin");

    assert_eq!(
        actual.len(),
        expected.len(),
        "jpeg_invert: length mismatch — got {} bytes ({}×{}×{}), expected {}",
        actual.len(),
        width,
        height,
        bands,
        expected.len()
    );

    // JPEG tolerance comparison: ±1 per channel on the checked fixture.
    let tolerance: i16 = 1;
    let mut max_diff = 0i16;
    let mut mismatch_count = 0usize;
    for (i, (&got, &exp)) in actual.iter().zip(expected.iter()).enumerate() {
        let diff = (got as i16 - exp as i16).abs();
        if diff > max_diff {
            max_diff = diff;
        }
        if diff > tolerance {
            mismatch_count += 1;
            if mismatch_count <= 5 {
                eprintln!(
                    "jpeg_invert: sample {i} diff={diff} (got={got}, exp={exp}) exceeds tolerance={tolerance}"
                );
            }
        }
    }
    assert_eq!(
        mismatch_count, 0,
        "jpeg_invert: {mismatch_count} samples exceeded tolerance={tolerance} (max_diff={max_diff})"
    );
}
